parameters.jsCode:
const output = items[0].json.output || {};
let codeNode = {};
try {
  codeNode = $('Process client message').first().json || {};
} catch (e) {
  codeNode = {};
}

const type = codeNode.type || "";
const commentId = codeNode.commentId || "";
const senderId = codeNode.senderId || "";
const postId = codeNode.postId || "";
const accountId = codeNode.accountId || "";

// Đọc trực tiếp các trường từ JSON do Structured Output Parser phân tích
const publicReply = output.publicReply || "";
const privateReply = output.privateReply || "";

return [{
  json: {
    type,
    commentId,
    postId,
    accountId,
    senderId,
    publicReply,
    privateReply
  }
}];

// 1. Lấy dữ liệu payload từ Zernio Webhook (hỗ trợ cả khi bọc trong 'body' hoặc ở ngoài root)
const payload = items[0].json.body || items[0].json || {};

const eventType = payload.event;

// ── TRƯỜNG HỢP 1: Nhận tin nhắn/postback từ Messenger/Instagram (Inbox) ──
if (eventType === 'message.received' || eventType === 'messaging_postbacks' || eventType === 'postback.received') {
  const message = payload.message || {};
  const conversation = payload.conversation || {};
  const account = payload.account || {};
  const postback = payload.postback || {};

  // Bỏ qua tin nhắn do chính Fanpage gửi đi (outgoing)
  if (message.direction === 'outgoing' || message.sender?.isSelf) return [];

  // Lấy nội dung tin nhắn hoặc payload của nút bấm (như nút Bắt đầu)
  const messageText = (message.text || postback.payload || payload.text || "").trim();

  return [{
    json: {
      type: 'message',
      senderId: message.sender?.id || postback.sender?.id || payload.senderId,
      conversationId: conversation.id || payload.conversationId,
      accountId: account.id || payload.accountId,
      messageText: messageText
    }
  }];
}

// ── TRƯỜNG HỢP 2: Nhận bình luận (Comment) trên bài viết ──
if (eventType === 'comment.received') {
  const comment = payload.comment || {};
  const account = payload.account || {};

  // Bỏ qua comment của chính Fanpage để tránh lặp (ID Fanpage: 106358191472644)
  if (comment.author?.id === '106358191472644' || comment.author?.name === 'Trọ Uni') return [];

  return [{
    json: {
      type: 'comment',
      commentId: comment.id,
      postId: comment.postId || comment.platformPostId,
      senderId: comment.author?.id,
      accountId: account.id,
      messageText: comment.text || ""
    }
  }];
}

return []; // Bỏ qua các sự kiện khác

