    "replies": ["Tiệc & Đám cưới", "Team Building", "Quay lại Menu"]
  },
  "vị trí & đi lại": {
    "text": "Bạn đang cần tìm đường đi hay phương tiện di chuyển đến bên mình thế?",
    "replies": ["Cách biển bao xa?", "Phương tiện đi lại", "Quay lại Menu"]
  },
  "cách biển bao xa?": {
    "text": "Khu nghỉ dưỡng bên mình nằm ở vị trí cực kỳ đắc địa, chỉ cách bãi biển Lộc An đúng 100m (khoảng 2 phút đi bộ là bạn đã ra tới biển để chạm cát và ngắm bình minh tuyệt đẹp rồi đó).",
    "replies": ["Phương tiện đi lại", "Quay lại Menu"]
  },
  "phương tiện đi lại": {
    "text": "Hiện tại bên mình chưa có xe đưa đón riêng của khu nghỉ dưỡng. Tuy nhiên, mình có thể gửi vị trí Google Maps chi tiết hoặc gợi ý các nhà xe khách limousine chất lượng cao đi thẳng từ TP.HCM/các tỉnh đến Lộc An cực tiện lợi cho bạn nhé.",
    "replies": ["Cách biển bao xa?", "Quay lại Menu"]
  }
};

const normalizedText = text.toLowerCase().trim();
let faqKey = "";

if (isWelcome) {
  faqKey = "welcome";
} else {
  faqKey = Object.keys(faq).find(key => key === normalizedText) || "";
}

if (normalizedText === "quay lại menu") {
  faqKey = "welcome";
}

if (faqKey && type === "message") {
  isFAQ = true;
  replyText = faq[faqKey].text;
  quickReplies = faq[faqKey].replies.map(title => {
    const cleanPayload = title.normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/đ/g, "d").replace(/Đ/g, "D")
      .replace(/&/g, "va")
      .replace(/[^a-zA-Z0-9\s]/g, "")
      .toUpperCase()
      .trim()
      .replace(/\s+/g, "_");
    return {
      "content_type": "text",
      "title": title,
      "payload": cleanPayload
    };
  });
}

return [{
  json: {
    ...item,
    isFAQ,
    replyText,
    quickReplies
  }
}];
